// frontend/src/pages/Dashboard.js
import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import PlaceCard from '../components/PlaceCard';
import Analytics from '../components/Analytics';
import Toast from '../components/Toast';
import ProfileModal from '../components/ProfileModal';
import AddPlaceModal from '../components/AddPlaceModal';
import { getPlaces, getPrediction, geocodeLocation } from '../services/api';

const CATEGORIES = [
  { key: 'all',        label: 'All',          icon: '🗺️' },
  { key: 'tourist',    label: 'Tourist',       icon: '🏛️' },
  { key: 'mall',       label: 'Malls',         icon: '🛍️' },
  { key: 'cafe',       label: 'Cafes',         icon: '☕' },
  { key: 'gym',        label: 'Gyms',          icon: '💪' },
  { key: 'restaurant', label: 'Restaurants',   icon: '🍽️' },
  { key: 'park',       label: 'Parks',         icon: '🌳' },
  { key: 'zoo',        label: 'Zoos',          icon: '🦁' },
];

const TABS = ['Explore', 'Add Place', 'Analytics'];

function getDistanceKm(lat1,lon1,lat2,lon2){
  const R=6371,dL=((lat2-lat1)*Math.PI)/180,dO=((lon2-lon1)*Math.PI)/180;
  const a=Math.sin(dL/2)**2+Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dO/2)**2;
  return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));
}
function formatDist(km){ return km<1?`${Math.round(km*1000)} m away`:`${km.toFixed(1)} km away`; }

async function reverseGeocode(lat,lng){
  try{
    const r=await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json`,{headers:{'Accept-Language':'en'}});
    const d=await r.json(); const a=d.address||{};
    return [a.suburb||a.neighbourhood,a.city||a.town||a.village].filter(Boolean).slice(0,2).join(', ')||'Your Location';
  }catch{ return 'Your Location'; }
}

export default function Dashboard() {
  const { user, logout } = useAuth();

  const [places, setPlaces]           = useState([]);
  const [predictions, setPred]        = useState({});
  const [category, setCategory]       = useState('all');
  const [search, setSearch]           = useState('');
  const [toast, setToast]             = useState(null);
  const [userCoords, setUserCoords]   = useState(null);
  const [locationName, setLocName]    = useState('');
  const [locLoading, setLocLoading]   = useState(false);
  const [manualLoc, setManualLoc]     = useState('');  // manual location input
  const [manualLoading, setManualLoading] = useState(false);
  const [loading, setLoading]         = useState(false);
  const [tab, setTab]                 = useState('Explore');
  const [lastUpdated, setLastUpd]     = useState(null);
  const [profileOpen, setProfile]     = useState(false);
  const [addPlaceOpen, setAddPlace]   = useState(false);
  const [mode, setMode]               = useState('idle');
  const refreshRef                    = useRef(null);

  const showToast = (msg, type='success') => setToast({ message: msg, type });

  const loadPlaces = useCallback(async (cat, q, coords, silent=false) => {
    if (!silent) setLoading(true);
    try {
      const lat = coords?.lat ?? userCoords?.lat ?? null;
      const lng = coords?.lng ?? userCoords?.lng ?? null;
      let data  = await getPlaces(cat, q, lat, lng);
      if (lat && lng) {
        data = data.map(p => {
          if (p.latitude && p.longitude && !p.distance_km) {
            const km = getDistanceKm(lat, lng, parseFloat(p.latitude), parseFloat(p.longitude));
            return { ...p, distance_km: km, distance_label: formatDist(km) };
          }
          return p;
        });
        if (!q) data.sort((a,b)=>(a.distance_km??99)-(b.distance_km??99));
      }
      setPlaces(data);
      setLastUpd(new Date());
      const entries = await Promise.all(data.map(p => getPrediction(p.id, p.category||'mall').then(pred=>[p.id,pred])));
      setPred(Object.fromEntries(entries));
    } catch {
      if (!silent) showToast('Could not load places. Make sure backend is running.', 'error');
    } finally {
      if (!silent) setLoading(false);
    }
  }, [userCoords]);

  useEffect(() => {
    if (mode==='idle') return;
    refreshRef.current = setInterval(() => loadPlaces(category, search, userCoords, true), 5*60*1000);
    return () => clearInterval(refreshRef.current);
  }, [category, search, userCoords, mode]);

  useEffect(() => {
    if (search.trim().length===0) {
      if (userCoords) { setMode('nearby'); const t=setTimeout(()=>loadPlaces(category,'',userCoords,false),300); return ()=>clearTimeout(t); }
      setPlaces([]); setMode('idle'); return;
    }
    setMode('search');
    const t = setTimeout(()=>loadPlaces(category, search, userCoords, false), 600);
    return ()=>clearTimeout(t);
  }, [search, category]);

  // GPS detect
  const detectLocation = () => {
    if (!navigator.geolocation) { showToast('Geolocation not supported.','error'); return; }
    setLocLoading(true); setLocName('Detecting...');
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const coords = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setUserCoords(coords);
        const name = await reverseGeocode(coords.lat, coords.lng);
        setLocName(name); setLocLoading(false); setMode('nearby');
        showToast(`📍 ${name} — Loading nearby places...`);
        loadPlaces(category, '', coords, false);
      },
      () => { setLocName(''); setLocLoading(false); showToast('Location access denied.','error'); },
      { enableHighAccuracy:true, timeout:10000 }
    );
  };

  // Manual location input
  const handleManualLocation = async (e) => {
    e.preventDefault();
    if (!manualLoc.trim()) return;
    setManualLoading(true);
    try {
      const data = await geocodeLocation(manualLoc.trim());
      setUserCoords({ lat: data.lat, lng: data.lng });
      setLocName(data.name);
      setMode('nearby');
      showToast(`📍 ${data.name} — Loading nearby places...`);
      loadPlaces(category, '', { lat: data.lat, lng: data.lng }, false);
      setManualLoc('');
    } catch {
      showToast('Location not found. Try a different name.', 'error');
    } finally {
      setManualLoading(false);
    }
  };

  const handleCategoryChange = (cat) => {
    setCategory(cat);
    if (mode!=='idle') loadPlaces(cat, search, userCoords, false);
  };

  const s = {
    page:    { minHeight:'100vh', background:'#f4f5f7', fontFamily:"'Inter',sans-serif" },
    nav:     { background:'#fff', borderBottom:'1px solid #eee', padding:'0 24px', height:'64px', display:'flex', alignItems:'center', justifyContent:'space-between', position:'sticky', top:0, zIndex:100 },
    logo:    { fontSize:'20px', fontWeight:'800', color:'#1a1a2e', letterSpacing:'-0.5px' },
    logoG:   { color:'#1D9E75' },
    navTabs: { display:'flex', gap:'4px' },
    navTab:  (a)=>({ padding:'8px 16px', border:'none', background:a?'#e8f8f2':'transparent', color:a?'#0f6e56':'#888', borderRadius:'10px', fontSize:'14px', fontWeight:a?'700':'500', cursor:'pointer' }),
    avatarBtn:{ display:'flex', alignItems:'center', gap:'8px', padding:'6px 12px', borderRadius:'40px', border:'1.5px solid #eee', background:'#fff', cursor:'pointer' },
    avatar:  { width:'32px', height:'32px', borderRadius:'50%', background:'linear-gradient(135deg,#1D9E75,#0f6e56)', color:'#fff', display:'flex', alignItems:'center', justifyContent:'center', fontWeight:'700', fontSize:'13px' },
    main:    { maxWidth:'1200px', margin:'0 auto', padding:'24px 20px', width:'100%' },
    card:    { background:'#fff', borderRadius:'16px', padding:'20px', border:'1.5px solid #f0f0f0', marginBottom:'16px' },
    grid:    { display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(300px,1fr))', gap:'16px' },
    empty:   { textAlign:'center', padding:'60px 20px', color:'#bbb' },
    input:   { width:'100%', padding:'12px 16px', boxSizing:'border-box', border:'1.5px solid #e8e8e8', borderRadius:'12px', fontSize:'14px', outline:'none', background:'#fafafa' },
    btn:     { padding:'12px 20px', background:'linear-gradient(135deg,#1D9E75,#0f6e56)', color:'#fff', border:'none', borderRadius:'12px', fontSize:'14px', fontWeight:'700', cursor:'pointer', whiteSpace:'nowrap' },
    label:   { display:'block', fontSize:'12px', fontWeight:'600', color:'#666', marginBottom:'6px', textTransform:'uppercase', letterSpacing:'0.4px' },
  };

  const renderIdle = () => (
    <div style={{ background:'linear-gradient(135deg,#f0fdf8,#e8f8f2)', border:'1.5px solid #b7ebd0', borderRadius:'20px', padding:'40px 24px', textAlign:'center' }}>
      <div style={{ fontSize:'48px', marginBottom:'14px' }}>📍</div>
      <div style={{ fontSize:'20px', fontWeight:'800', color:'#0f6e56', marginBottom:'8px' }}>Discover Places Around You</div>
      <div style={{ fontSize:'14px', color:'#888', marginBottom:'28px', lineHeight:1.6 }}>
        Use GPS or enter your city/area to find malls, cafes, gyms, parks, zoos & tourist spots with crowd predictions.
      </div>

      {/* GPS button */}
      <button onClick={detectLocation} style={{ ...s.btn, fontSize:'15px', padding:'14px 28px', marginBottom:'20px' }}>
        📍 Detect My Location (GPS)
      </button>

      {/* Manual location */}
      <div style={{ fontSize:'13px', color:'#bbb', marginBottom:'12px' }}>— or enter location manually —</div>
      <form onSubmit={handleManualLocation} style={{ display:'flex', gap:'8px', maxWidth:'400px', margin:'0 auto 24px' }}>
        <input
          style={{ ...s.input, flex:1 }}
          placeholder="e.g. Patna, Connaught Place..."
          value={manualLoc}
          onChange={e=>setManualLoc(e.target.value)}
        />
        <button type="submit" style={s.btn} disabled={manualLoading}>
          {manualLoading ? '...' : 'Go'}
        </button>
      </form>

      {/* Quick suggestions */}
      <div style={{ fontSize:'12px', color:'#bbb', marginBottom:'10px', textTransform:'uppercase', letterSpacing:'0.5px' }}>Quick search</div>
      <div style={{ display:'flex', gap:'8px', justifyContent:'center', flexWrap:'wrap' }}>
        {['India Gate','Patna Zoo','Taj Mahal','DLF Mall','Starbucks','Lodhi Garden'].map(s => (
          <button key={s} onClick={()=>setSearch(s)} style={{ padding:'7px 14px', background:'#fff', border:'1.5px solid #ddd', borderRadius:'20px', fontSize:'13px', color:'#555', cursor:'pointer' }}>{s}</button>
        ))}
      </div>
    </div>
  );

  return (
    <div style={s.page}>
      {/* Navbar */}
      <nav style={s.nav}>
        <div style={s.logo}>Visit<span style={s.logoG}>Wise</span> AI</div>
        <div style={s.navTabs}>
          {TABS.map(t => <button key={t} style={s.navTab(tab===t)} onClick={()=>setTab(t)}>{t}</button>)}
        </div>
        <button style={s.avatarBtn} onClick={()=>setProfile(true)}>
          <div style={s.avatar}>{user?.name?.charAt(0).toUpperCase()}</div>
          <span style={{ fontSize:'14px', fontWeight:'600', color:'#1a1a2e' }}>{user?.name?.split(' ')[0]}</span>
          <span style={{ fontSize:'11px', color:'#bbb' }}>▼</span>
        </button>
      </nav>

      <div style={s.main}>

        {/* ── EXPLORE TAB ── */}
        {tab==='Explore' && (
          <>
            {/* Search + GPS + Manual Location row */}
            <div style={{ display:'flex', gap:'10px', marginBottom:'12px', flexWrap:'wrap' }}>
              {/* Search box */}
              <div style={{ flex:2, minWidth:'200px', position:'relative' }}>
                <span style={{ position:'absolute', left:'15px', top:'50%', transform:'translateY(-50%)', fontSize:'16px', pointerEvents:'none' }}>🔍</span>
                <input
                  style={{ width:'100%', padding:'13px 18px 13px 46px', boxSizing:'border-box', border:'1.5px solid #e8e8e8', borderRadius:'14px', fontSize:'14px', outline:'none', background:'#fff', boxShadow:'0 2px 8px rgba(0,0,0,0.04)' }}
                  placeholder="Search India Gate, Patna Zoo, DLF Mall..."
                  value={search}
                  onChange={e=>setSearch(e.target.value)}
                  onFocus={e=>e.target.style.borderColor='#1D9E75'}
                  onBlur={e=>e.target.style.borderColor='#e8e8e8'}
                />
              </div>

              {/* GPS button */}
              <button style={{ padding:'13px 16px', background:userCoords?'#1D9E75':'#1a1a2e', color:'#fff', border:'none', borderRadius:'14px', fontSize:'13px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap', display:'flex', alignItems:'center', gap:'6px' }}
                onClick={detectLocation} disabled={locLoading}>
                {locLoading?'⏳ Detecting...':<><span>📍</span>{userCoords?locationName||'Location On':'GPS'}</>}
              </button>
            </div>

            {/* Manual location input row */}
            <form onSubmit={handleManualLocation} style={{ display:'flex', gap:'8px', marginBottom:'14px' }}>
              <div style={{ flex:1, position:'relative' }}>
                <span style={{ position:'absolute', left:'14px', top:'50%', transform:'translateY(-50%)', fontSize:'15px', pointerEvents:'none' }}>🏙️</span>
                <input
                  style={{ width:'100%', padding:'11px 14px 11px 40px', boxSizing:'border-box', border:'1.5px solid #e8e8e8', borderRadius:'12px', fontSize:'13px', outline:'none', background:'#fff' }}
                  placeholder="Enter city or area manually (e.g. Patna, Connaught Place, Koramangala)"
                  value={manualLoc}
                  onChange={e=>setManualLoc(e.target.value)}
                  onFocus={e=>e.target.style.borderColor='#1D9E75'}
                  onBlur={e=>e.target.style.borderColor='#e8e8e8'}
                />
              </div>
              <button type="submit" disabled={manualLoading} style={{ padding:'11px 20px', background:'#1a1a2e', color:'#fff', border:'none', borderRadius:'12px', fontSize:'13px', fontWeight:'600', cursor:'pointer', whiteSpace:'nowrap' }}>
                {manualLoading?'Searching...':'Set Location'}
              </button>
            </form>

            {/* Location pill */}
            {userCoords && locationName && (
              <div style={{ display:'inline-flex', alignItems:'center', gap:'6px', background:'#e8f8f2', color:'#0f6e56', padding:'7px 14px', borderRadius:'40px', fontSize:'13px', fontWeight:'600', marginBottom:'14px', border:'1.5px solid #b7ebd0' }}>
                📍 <strong>{locationName}</strong>
                <span style={{ fontSize:'11px', opacity:0.7, fontWeight:'400' }}> · {mode==='nearby'?'Showing nearby places':'Sorted by distance'}</span>
              </div>
            )}

            {/* Category filter — Tourist included */}
            <div style={{ display:'flex', gap:'8px', marginBottom:'16px', flexWrap:'wrap' }}>
              {CATEGORIES.map(c=>(
                <button key={c.key}
                  style={{ padding:'8px 14px', display:'flex', alignItems:'center', gap:'6px', border:'1.5px solid '+(category===c.key?'#1D9E75':'#e8e8e8'), borderRadius:'40px', background:category===c.key?'#e8f8f2':'#fff', color:category===c.key?'#0f6e56':'#666', fontSize:'13px', fontWeight:category===c.key?'700':'500', cursor:'pointer' }}
                  onClick={()=>handleCategoryChange(c.key)}>
                  {c.icon} {c.label}
                </button>
              ))}
            </div>

            {/* Result meta */}
            {!loading && places.length>0 && (
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'14px', flexWrap:'wrap', gap:'8px' }}>
                <span style={{ fontSize:'13px', color:'#aaa' }}>
                  {places.length} {mode==='nearby'?'nearby places':`results for "${search}"`}
                  {userCoords?' · Sorted by distance':''}
                  {lastUpdated?` · ${lastUpdated.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'})}`:''}
                </span>
                <button onClick={()=>loadPlaces(category,search,userCoords,false)} style={{ padding:'6px 14px', border:'1.5px solid #e8e8e8', background:'#fff', color:'#888', borderRadius:'20px', fontSize:'12px', cursor:'pointer', fontWeight:'600' }}>🔄 Refresh</button>
              </div>
            )}

            {/* Places */}
            {loading ? (
              <div style={s.empty}><div style={{ fontSize:'36px', marginBottom:'12px' }}>⏳</div><div style={{ fontWeight:'600', color:'#888' }}>{mode==='nearby'?'Finding nearby places...':`Searching for "${search}"...`}</div></div>
            ) : places.length>0 ? (
              <div style={s.grid}>{places.map(p=><PlaceCard key={p.id} place={p} prediction={predictions[p.id]}/>)}</div>
            ) : renderIdle()}
          </>
        )}

        {/* ── ADD PLACE TAB ── */}
        {tab==='Add Place' && (
          <div style={{ maxWidth:'520px', margin:'0 auto' }}>
            <div style={{ marginBottom:'20px' }}>
              <h2 style={{ fontSize:'20px', fontWeight:'800', color:'#1a1a2e', marginBottom:'6px' }}>Add a New Place</h2>
              <p style={{ fontSize:'14px', color:'#888' }}>Add any place — mall, tourist spot, zoo, park, restaurant — that is missing from search results.</p>
            </div>
            <AddPlaceForm onSuccess={(name)=>{ showToast(`"${name}" added successfully!`); setTab('Explore'); }} />
          </div>
        )}

        {/* ── ANALYTICS TAB ── */}
        {tab==='Analytics' && <Analytics userCoords={userCoords} />}
      </div>

      {profileOpen && <ProfileModal user={user} onClose={()=>setProfile(false)} onLogout={logout}/>}
      {toast && <Toast message={toast.message} type={toast.type} onClose={()=>setToast(null)}/>}
    </div>
  );
}

// ── Inline Add Place Form ─────────────────────────────────
function AddPlaceForm({ onSuccess }) {
  const CATS = ['mall','cafe','gym','restaurant','park','zoo','tourist','cinema'];
  const [form, setForm]     = useState({ name:'', category:'tourist', address:'', latitude:'', longitude:'' });
  const [loading, setLoad]  = useState(false);
  const [error, setError]   = useState('');
  const [locating, setLoc]  = useState(false);

  const update = (k,v) => setForm(f=>({...f,[k]:v}));

  const useGPS = () => {
    if (!navigator.geolocation) return;
    setLoc(true);
    navigator.geolocation.getCurrentPosition(pos=>{
      update('latitude',  pos.coords.latitude.toFixed(6));
      update('longitude', pos.coords.longitude.toFixed(6));
      setLoc(false);
    },()=>setLoc(false));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.name.trim()) { setError('Place name is required'); return; }
    setLoad(true); setError('');
    try {
      const res = await fetch('http://localhost:5000/api/places', {
        method:'POST',
        headers:{ 'Content-Type':'application/json', 'Authorization':`Bearer ${localStorage.getItem('vw_token')}` },
        body: JSON.stringify(form),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error||'Failed');
      onSuccess(form.name);
      setForm({ name:'', category:'tourist', address:'', latitude:'', longitude:'' });
    } catch(err) {
      setError(err.message);
    } finally { setLoad(false); }
  };

  const s = {
    card:  { background:'#fff', borderRadius:'16px', padding:'24px', border:'1.5px solid #f0f0f0' },
    label: { display:'block', fontSize:'12px', fontWeight:'600', color:'#666', marginBottom:'6px', textTransform:'uppercase', letterSpacing:'0.4px' },
    input: { width:'100%', padding:'12px 14px', boxSizing:'border-box', border:'1.5px solid #e8e8e8', borderRadius:'10px', fontSize:'14px', outline:'none', background:'#fafafa', marginBottom:'16px' },
  };

  return (
    <div style={s.card}>
      {error && <div style={{ background:'#fdecea', color:'#c0392b', borderRadius:'10px', padding:'10px 14px', fontSize:'13px', marginBottom:'16px' }}>⚠️ {error}</div>}
      <form onSubmit={handleSubmit}>
        <label style={s.label}>Place Name *</label>
        <input style={s.input} placeholder="e.g. India Gate, Patna Zoo, DLF Mall" value={form.name} onChange={e=>update('name',e.target.value)} required />

        <label style={s.label}>Category</label>
        <select style={{ ...s.input, appearance:'none', cursor:'pointer' }} value={form.category} onChange={e=>update('category',e.target.value)}>
          {CATS.map(c=><option key={c} value={c}>{c.charAt(0).toUpperCase()+c.slice(1)}</option>)}
        </select>

        <label style={s.label}>Address / City</label>
        <input style={s.input} placeholder="e.g. Rajpath, New Delhi" value={form.address} onChange={e=>update('address',e.target.value)} />

        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'10px', marginBottom:'0' }}>
          <div>
            <label style={s.label}>Latitude</label>
            <input style={{ ...s.input }} placeholder="28.6129" value={form.latitude} onChange={e=>update('latitude',e.target.value)} type="number" step="any" />
          </div>
          <div>
            <label style={s.label}>Longitude</label>
            <input style={{ ...s.input }} placeholder="77.2295" value={form.longitude} onChange={e=>update('longitude',e.target.value)} type="number" step="any" />
          </div>
        </div>

        <button type="button" onClick={useGPS} disabled={locating} style={{ width:'100%', padding:'10px', background:'#f7f8fc', border:'1.5px dashed #ddd', borderRadius:'10px', fontSize:'13px', color:'#888', cursor:'pointer', marginBottom:'20px' }}>
          {locating ? '⏳ Getting location...' : '📍 Use My Current GPS Location'}
        </button>

        <button type="submit" disabled={loading} style={{ width:'100%', padding:'14px', background:'linear-gradient(135deg,#1D9E75,#0f6e56)', color:'#fff', border:'none', borderRadius:'12px', fontSize:'15px', fontWeight:'700', cursor:'pointer' }}>
          {loading ? 'Adding...' : '+ Add Place'}
        </button>
      </form>
    </div>
  );
}
